using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection for HttpClient and ILogger.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the API. Returns JSON array of user objects.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (1-100)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing users with limit {Limit}", limit);
        var response = await httpClient.GetAsync($"/users?_limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var users = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(users, JsonOptions);
    }

    [McpServerTool, Description("Get a single user by their numeric ID. Returns a JSON user object.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var user = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(user, JsonOptions);
    }

    [McpServerTool, Description("Create a new user. Returns the created user object as JSON.")]
    public async Task<string> CreateUser(
        [Description("User's full name")] string name,
        [Description("User's email address")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name} <{Email}>", name, email);
        var payload = new { name, email };
        var response = await httpClient.PostAsJsonAsync("/users", payload, cancellationToken);
        response.EnsureSuccessStatusCode();

        var created = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(created, JsonOptions);
    }
}

